const response = $input.first().json;
const documents = response.documents || [];
const cityMap = {};

for (const doc of documents) {
  const f = doc.fields || {};
  const city = f.localidad?.stringValue;
  const fcmToken = f.fcmToken?.stringValue;
  const uid = doc.name.split('/').pop();
  const email = f.email?.stringValue || '';

  if (city && fcmToken) {
    if (!cityMap[city]) cityMap[city] = [];
    cityMap[city].push({ uid, fcmToken, email });
  }
}

return Object.entries(cityMap).map(([city, users]) => ({
  json: { city, users }
}));

const city = $json.city || '';
const cityTag = city.normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\s+/g, '').toLowerCase();
const hashtags = [
  `torneo${cityTag}`,
  'torneotcg',
  'torneomtg',
  'torneoyugioh',
  'torneopokemon',
  'pokemontcg',
  'magictcg',
  'yugiohtorneo'
];
const directUrls = hashtags.map(h => `https://www.instagram.com/explore/tags/${h}/`);
return [{ json: { ...$json, cityTag, directUrls } }];

const items = $input.all();
const normalized = [];
const city = $('Por Cada Ciudad').first().json.city || '';

for (const item of items) {
  const data = item.json;

  // Formato Instagram via Apify - items individuales
  if (data.shortCode || data.inputUrl?.includes('instagram.com')) {
    const url = data.url || (data.shortCode ? `https://www.instagram.com/p/${data.shortCode}/` : null);
    if (!url) continue;
    normalized.push({
      json: {
        platform: 'instagram',
        sourceUrl: url,
        text: data.caption || '',
        imageUrl: data.displayUrl || data.imageUrl || null,
        hashtags: (data.hashtags || []).map(h => '#' + h),
        rawDate: data.timestamp || new Date().toISOString(),
        city: data.locationName || city
      }
    });
    continue;
  }

  // Formato Instagram via Apify - array (fallback)
  if (Array.isArray(data)) {
    for (const post of data) {
      const url = post.url || (post.shortCode ? `https://www.instagram.com/p/${post.shortCode}/` : null);
      if (!url) continue;
      normalized.push({
        json: {
          platform: 'instagram',
          sourceUrl: url,
          text: post.caption || '',
          imageUrl: post.displayUrl || post.imageUrl || null,
          hashtags: (post.hashtags || []).map(h => '#' + h),
          rawDate: post.timestamp || new Date().toISOString(),
          city: post.locationName || city
        }
      });
    }
  }

  // Formato Reddit
  if (data.data?.children) {
    for (const post of data.data.children) {
      const p = post.data;
      normalized.push({
        json: {
          platform: 'reddit',
          sourceUrl: `https://reddit.com${p.permalink}`,
          text: `${p.title} ${p.selftext || ''}`,
          imageUrl: p.url_overridden_by_dest?.match(/\.(jpg|png|gif|jpeg)/i)
            ? p.url_overridden_by_dest : null,
          hashtags: [],
          rawDate: new Date(p.created_utc * 1000).toISOString(),
          city: city
        }
      });
    }
  }
}

return normalized.length > 0 ? normalized : [{ json: { skip: true } }];

const imageUrl = $json.imageUrl;
try {
  const responseBuffer = await $helpers.httpRequest({
    method: 'GET',
    url: imageUrl,
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
      'Referer': 'https://www.instagram.com/',
      'Accept': 'image/webp,image/apng,image/*,*/*;q=0.8'
    },
    encoding: 'arraybuffer',
    returnFullResponse: false
  });
  const base64 = Buffer.from(responseBuffer).toString('base64');
  const visionBody = JSON.stringify({
    requests: [{
      image: { content: base64 },
      features: [
        { type: 'TEXT_DETECTION', maxResults: 1 },
        { type: 'LABEL_DETECTION', maxResults: 10 }
      ]
    }]
  });
  return [{ json: { ...$json, visionBody } }];
} catch (e) {
  return [{ json: { ...$json, visionBody: null, downloadError: e.message } }];
}

const visionResponse = $input.first().json;
const originalPost = $('Tiene Imagen').first().json;

const response = visionResponse.responses?.[0] || {};
const fullText = (response.textAnnotations?.[0]?.description || '').toLowerCase();
const labels   = (response.labelAnnotations || []).map(l => l.description.toLowerCase());

const games = [
  { key: 'Pokemon',  terms: ['pokemon', 'pokémon', 'pkmn'] },
  { key: 'Magic',    terms: ['magic', 'mtg', 'commander'] },
  { key: 'YuGiOh',  terms: ['yugioh', 'yu-gi-oh', 'ygo'] },
  { key: 'OnePiece',terms: ['one piece', 'optcg'] },
  { key: 'Lorcana', terms: ['lorcana'] },
  { key: 'FaB',     terms: ['flesh and blood', 'fab'] }
];

let juego = null;
for (const g of games) {
  if (g.terms.some(t => fullText.includes(t) || labels.some(l => l.includes(t)))) {
    juego = g.key;
    break;
  }
}

const esTorneo =
  fullText.includes('torneo') ||
  fullText.includes('tournament') ||
  fullText.includes('campeonato') ||
  labels.some(l => ['card game', 'games', 'tabletop game', 'collectible card game'].includes(l));

// Extraer primera línea como título aproximado
const titulo = response.textAnnotations?.[0]?.description
  ?.split('\n')
  .find(l => l.trim().length > 3) || null;

return [{ json: { ...originalPost, analysis: { esTorneo, titulo, fecha: null, lugar: originalPost.city || null, juego } } }];

const post = $input.first().json;
const text = (post.text || '').toLowerCase();
const hashtags = post.hashtags || [];

const games = [
  { key: 'Pokemon',  terms: ['pokemon', 'pokémon', 'pkmn'] },
  { key: 'Magic',    terms: ['magic', 'mtg', 'commander'] },
  { key: 'YuGiOh',  terms: ['yugioh', 'yu-gi-oh', 'ygo'] },
  { key: 'OnePiece',terms: ['one piece', 'optcg'] },
  { key: 'Lorcana', terms: ['lorcana'] },
  { key: 'FaB',     terms: ['flesh and blood', 'fab'] }
];

let juego = null;
for (const g of games) {
  if (g.terms.some(t => text.includes(t) || hashtags.some(h => h.toLowerCase().includes(t)))) {
    juego = g.key;
    break;
  }
}

const esTorneo = text.includes('torneo') || text.includes('tournament') || text.includes('campeonato');

return [{
  json: {
    ...post,
    analysis: { esTorneo, titulo: null, fecha: null, lugar: post.city || null, juego }
  }
}];

const queryResult = $input.all();
const postData = $('Es Torneo').first().json;

const exists = queryResult.some(r => r.json.document);

return [{ json: { ...postData, isDuplicate: exists } }];

