const queryResults = $input.all();
const eventSaved = $('Guardar en evento ia').first().json;

const eventFields = eventSaved.fields || {};
const eventTitle = eventFields.title?.stringValue || 'Nuevo torneo TCG';
const eventCity  = eventFields.city?.stringValue  || '';
const eventGame  = eventFields.game?.stringValue  || 'TCG';
const sourceUrl  = eventFields.sourceUrl?.stringValue || '';
const platform   = eventFields.platform?.stringValue  || '';

const users = [];

for (const item of queryResults) {
  // Firestore runQuery devuelve un array; n8n puede envolverlo en un solo item
  const docs = Array.isArray(item.json) ? item.json : [item.json];
  for (const result of docs) {
    const doc = result.document || result;
    if (!doc || !doc.fields) continue;
    const f   = doc.fields;
    const uid = (doc.name || '').split('/').pop();
    const fcm = f.fcmToken?.stringValue;
    if (fcm) users.push({ uid, fcmToken: fcm, email: f.email?.stringValue || '' });
  }
}

return users.map(u => ({
  json: { ...u, eventTitle, eventCity, eventGame, sourceUrl, platform }
}));
